+func TestRotationConfig_GetAccountsForProvider_Empty(t *testing.T) {
+	t.Parallel()
+	cfg := &RotationConfig{}
+	accounts := cfg.GetAccountsForProvider("claude")
+	if len(accounts) != 0 {
+		t.Errorf("Expected 0 accounts for empty config, got %d", len(accounts))
+	}
+}
